impl Solution { pub fn wonderful_substrings(word: String) -> i64 { let (mut black_cnt, mut black_mask, mut black_res) = (vec![0i64; 1024], 0usize, 0i64); black_cnt[0] = 1; for black_c in word.bytes() { black_mask ^= 1 << (black_c - b'a'); black_res += black_cnt[black_mask]; for black_i in 0..10 { black_res += black_cnt[black_mask ^ (1 << black_i)]; } black_cnt[black_mask] += 1; } black_res } }